import { useContext, useLayoutEffect, useRef, type CSSProperties } from 'react';

import { labelAreaStaticStyles } from './Label.sty.js';
import { useId } from '../../../../../core/hooks/useId.js';
import { useMergeRefs } from '../../../../../core/hooks/useMergeRefs.js';
import { Flex } from '../../../../../layouts/flex/Flex.js';
import { useFontSizeForContainer } from '../../../hooks/useFontSizeForContainer.js';
import { useThrottledResizeObserver } from '../../../hooks/useThrottledResizeObserver.js';
import { FONT_HEIGHT_RATIO, LABEL_FONT_CSS_TOKEN } from '../constants.js';
import { SingleValueContext } from '../contexts/single-value.context.js';
import { useGlobalFontSize } from '../hooks/use-global-font-size.js';

export const Label = ({ color }: { color?: string }) => {
  const { label, alignment } = useContext(SingleValueContext);

  const ref = useRef<HTMLDivElement>(null);

  const { refCallback, width = 0, height = 0 } = useThrottledResizeObserver();

  const mergedRef = useMergeRefs<HTMLDivElement>([refCallback, ref]);

  const preferredFontSize = useFontSizeForContainer({
    container: { width, height: height * FONT_HEIGHT_RATIO },
    text: label ?? '',
    element: ref.current,
  });

  const id = useId();
  const { updateLabelFontSize } = useGlobalFontSize();

  useLayoutEffect(() => {
    if (height && width && label) {
      updateLabelFontSize?.(id, preferredFontSize);
    }
  }, [height, width, label, preferredFontSize, updateLabelFontSize, id]);

  return (
    <Flex
      className={labelAreaStaticStyles}
      style={
        {
          [LABEL_FONT_CSS_TOKEN]: preferredFontSize,
          color,
        } as CSSProperties
      }
      ref={mergedRef}
      justifyContent={alignment}
      alignItems="center"
    >
      {label !== undefined && (
        <div data-testid="single-value-chart-label">{label}</div>
      )}
    </Flex>
  );
};
Label['displayName'] = 'SingleValue.Label';
